            ))}
        </div>
        {selectedDay && (
            <div className="mt-4 p-3 bg-rose-500/10 border border-rose-500/20 rounded-lg text-center">
                <p className="text-rose-200 text-sm">Agendado! O app enviará um lembrete.</p>
