    Se perguntarem sobre locais, use a ferramenta Google Maps para encontrar lugares reais próximos.
    Se perguntarem sobre equipamentos, dê opções econômicas e "pro".
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash', // Use flash for speed, maps tool is available on flash
    contents: message,
    config: {
        systemInstruction: systemInstruction,
        tools: [{ googleMaps: {} }],
        toolConfig: toolConfig
    }
  });

  // Extract text and potential map links
  let text = response.text || "";
  const mapChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

  // Append map links to text if they exist (simple formatting)
  if (mapChunks.length > 0) {
      text += "\n\n**Sugestões de Locais:**\n";
      mapChunks.forEach((chunk: any) => {
          if (chunk.web?.uri) {
             text += `- [${chunk.web.title}](${chunk.web.uri})\n`;
          }
      });
  }

  return text;
};

import React, { useState, useEffect } from 'react';
import { Navbar } from './components/Navbar';
import { Quiz } from './components/Quiz';
import { Pathfinder } from './components/Pathfinder';
import { ActionCenter } from './components/ActionCenter';
import { Tab, Archetype, Journey } from './types';

export default function App() {
  const [currentTab, setCurrentTab] = useState<Tab>('explore');
  const [userArchetype, setUserArchetype] = useState<Archetype | null>(null);
  const [selectedSport, setSelectedSport] = useState<string>('');
  const [currentJourney, setCurrentJourney] = useState<Journey | null>(null);

  // Load from local storage on mount
  useEffect(() => {
    const savedArchetype = localStorage.getItem('neuroflow_archetype');
    const savedJourney = localStorage.getItem('neuroflow_journey');

    if (savedArchetype) setUserArchetype(JSON.parse(savedArchetype));
    if (savedJourney) {
        const parsed = JSON.parse(savedJourney);
        setCurrentJourney(parsed);
        setSelectedSport(parsed.sport);
    }
  }, []);

  const handleArchetypeComplete = (archetype: Archetype) => {
    setUserArchetype(archetype);
    localStorage.setItem('neuroflow_archetype', JSON.stringify(archetype));
  };

  const handleResetArchetype = () => {
    setUserArchetype(null);
    localStorage.removeItem('neuroflow_archetype');
    // Optionally keep the journey or clear it too? Let's keep the journey to not be destructive unless intentional.
    // If we want a full reset:
    // setCurrentJourney(null);
    // localStorage.removeItem('neuroflow_journey');
    // setSelectedSport('');
  };

  const handleSaveJourney = (journey: Journey) => {
    setCurrentJourney(journey);
    localStorage.setItem('neuroflow_journey', JSON.stringify(journey));
  };

  const renderContent = () => {
    switch (currentTab) {
      case 'explore':
        return (
          <Quiz 
            onComplete={handleArchetypeComplete} 
            setSport={setSelectedSport}
            goToJourney={() => setCurrentTab('journey')}
            existingArchetype={userArchetype}
            onReset={handleResetArchetype}
          />
        );
      case 'journey':
        return (
          <Pathfinder 
            sport={selectedSport} 
            existingJourney={currentJourney}
            saveJourney={handleSaveJourney}
            goToAction={() => setCurrentTab('action')}
          />
        );
      case 'action':
        return <ActionCenter journey={currentJourney} />;
      default:
        return null;
    }
  };

  return (
    <div className="bg-slate-900 min-h-screen text-slate-50">
      <main className="max-w-md mx-auto min-h-screen bg-slate-900 shadow-2xl overflow-hidden relative">
        {renderContent()}
      </main>
      <Navbar currentTab={currentTab} onTabChange={setCurrentTab} />
    </div>
  );
}

