export const Quiz: React.FC<QuizProps> = ({ onComplete, setSport, goToJourney, existingArchetype, onReset }) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [answers, setAnswers] = useState<QuizAnswer[]>([]);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<Archetype | null>(null);

  // Visual state to handle selection highlight and delay
  const [selectedOptionIdx, setSelectedOptionIdx] = useState<number | null>(null);

  // Initialize with existing data if present
  useEffect(() => {
    if (existingArchetype) {
      setResult(existingArchetype);
    } else {
      setResult(null);
      setCurrentStep(0);
      setAnswers([]);
    }
  }, [existingArchetype]);

  const handleOptionClick = (option: any, idx: number) => {
    // 1. Visually select immediately
    setSelectedOptionIdx(idx);

    // 2. Wait for visual feedback before moving
    setTimeout(() => {
        handleAnswerLogic(option);
    }, 400); // 400ms delay for better UX
  };

  const handleAnswerLogic = async (option: any) => {
    const newAnswer: QuizAnswer = {
      questionId: QUESTIONS[currentStep].id,
      scenario: QUESTIONS[currentStep].scenario,
      selectedOption: option.text,
      category: QUESTIONS[currentStep].category as any,
    };

    const newAnswers = [...answers, newAnswer];
    setAnswers(newAnswers);
    setSelectedOptionIdx(null); // Reset visual selection for next slide

    if (currentStep < QUESTIONS.length - 1) {
      setCurrentStep(prev => prev + 1);
    } else {
      // Finish Quiz
      setLoading(true);
      try {
        const archetype = await analyzeNeuroArchetype(newAnswers);
        setResult(archetype);
        onComplete(archetype);
      } catch (error) {
        console.error("Error analyzing quiz:", error);
        alert("Ops! A IA teve um bloqueio criativo. Tente novamente.");
        // Rollback simple error handling
        setCurrentStep(prev => prev - 1);
        setAnswers(prev => prev.slice(0, -1));
      } finally {
        setLoading(false);
      }
    }
  };

  const handleBack = () => {
    if (currentStep > 0) {
      setCurrentStep(prev => prev - 1);
      setAnswers(prev => prev.slice(0, -1)); // Remove last answer
    }
  };

  const handleRetake = () => {
    onReset();
    setResult(null);
    setCurrentStep(0);
    setAnswers([]);
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center h-[60vh] text-center px-6 animate-fade-in">
        <div className="animate-spin mb-6">
          <BrainIcon className="w-16 h-16 text-teal-400" />
        </div>
        <h3 className="text-2xl font-bold text-white mb-2">Processando Neuroquímica...</h3>
        <p className="text-slate-400 text-sm">Cruzando seus dados de dopamina, tolerância social e foco.</p>
      </div>
    );
  }

  if (result) {
    return (
      <div className="p-6 pb-24 animate-fade-in">
        <div className="bg-slate-800 rounded-3xl p-8 shadow-2xl border border-slate-700 relative overflow-hidden">
          {/* Background decoration */}
          <div className="absolute top-0 right-0 w-32 h-32 bg-teal-500/10 rounded-full blur-3xl -mr-10 -mt-10"></div>

          <div className="flex items-center justify-between mb-6 relative z-10">
            <span className="text-xs uppercase tracking-widest text-teal-400 font-bold">Diagnóstico Completo</span>
            <button 
                onClick={handleRetake} 
                className="flex items-center space-x-2 text-slate-500 hover:text-white transition-colors text-xs font-medium"
            >
                <RefreshIcon className="w-4 h-4" />
                <span>Refazer</span>
            </button>
          </div>

          <div className="mb-8 relative z-10">
             <h2 className="text-4xl font-bold text-white mb-2 tracking-tight">{result.name}</h2>
             <div className="inline-block bg-purple-500/20 text-purple-200 px-3 py-1 rounded-full text-xs font-semibold mb-4 border border-purple-500/30">
                {result.neurochemistry}
             </div>
             <p className="text-slate-300 leading-relaxed text-sm border-l-2 border-teal-500 pl-4">
                {result.description}
             </p>
          </div>

          <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-4">Esportes Compatíveis</h3>
          <div className="space-y-3 relative z-10">
            {result.suggestedSports.map((sport, idx) => (
              <button
                key={idx}
                onClick={() => {
                  setSport(sport);
                  goToJourney();
                }}
                className="w-full text-left p-4 rounded-xl bg-slate-700/50 hover:bg-slate-700 border border-slate-600/50 hover:border-teal-500/50 transition-all group"
              >
                <div className="flex justify-between items-center">
                  <span className="font-semibold text-white text-lg">{sport}</span>
                  <span className="text-teal-400 text-sm opacity-0 group-hover:opacity-100 -translate-x-2 group-hover:translate-x-0 transition-all duration-300">
                    Criar Plano &rarr;
                  </span>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  const question = QUESTIONS[currentStep];

  return (
    <div className="p-6 pb-24 max-w-lg mx-auto">
      {/* Header with Progress and Back Button */}
      <div className="mb-8">
        <div className="flex justify-between items-center mb-6">
            <div className="flex items-center">
                {currentStep > 0 ? (
                    <button onClick={handleBack} className="mr-3 p-1 rounded-full hover:bg-slate-800 text-slate-400 hover:text-white transition-colors">
                        <ChevronLeftIcon className="w-6 h-6" />
                    </button>
                ) : (
                    <div className="w-8 mr-3"></div> // Spacer to keep title aligned
                )}
                <span className="text-xs font-bold text-slate-500 tracking-widest uppercase">
                    Passo {currentStep + 1} de {QUESTIONS.length}
                </span>
            </div>
            <BrainIcon className="w-5 h-5 text-teal-500 opacity-50" />
        </div>

        {/* Animated Progress Bar */}
        <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden">
            <div 
                className="h-full bg-gradient-to-r from-teal-600 to-teal-400 rounded-full transition-all duration-500 ease-out"
                style={{ width: `${((currentStep + 1) / QUESTIONS.length) * 100}%` }}
            ></div>
        </div>
      </div>

      {/* Question Container - Key forces re-render animation on step change */}
      <div key={currentStep} className="animate-fade-in">
        <h2 className="text-2xl font-bold text-white mb-2 leading-tight">
            {question.scenario}
        </h2>
        <p className="text-slate-400 text-sm mb-8 italic opacity-80">
            Seja honesto, ninguém está vendo.
        </p>

        <div className="space-y-4">
            {question.options.map((option, idx) => {
                const isSelected = selectedOptionIdx === idx;
                return (
                    <button
                        key={idx}
                        onClick={() => handleOptionClick(option, idx)}
                        disabled={selectedOptionIdx !== null} // Prevent double clicking during transition
                        className={`w-full text-left p-5 rounded-2xl border-2 transition-all duration-200 shadow-md group relative overflow-hidden
                            ${isSelected 
                                ? 'bg-teal-500/10 border-teal-500 transform scale-[1.02]' 
                                : 'bg-slate-800 border-transparent hover:border-slate-600 hover:bg-slate-750'
                            }
                        `}
                    >
                        <div className="flex items-center relative z-10">
                            <div className={`
                                w-8 h-8 rounded-full flex items-center justify-center mr-4 font-bold text-sm transition-colors
                                ${isSelected 
                                    ? 'bg-teal-500 text-white' 
                                    : 'bg-slate-700 text-slate-400 group-hover:bg-slate-600 group-hover:text-white'
                                }
                            `}>
                                {String.fromCharCode(65 + idx)}
                            </div>
                            <span className={`font-medium transition-colors ${isSelected ? 'text-white' : 'text-slate-200'}`}>
                                {option.text}
                            </span>
                        </div>
                    </button>
                );
            })}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Journey, JourneyStep } from '../types';
import { generateJourneySteps, getChatAssistance } from '../services/geminiService';
import { MapIcon, CheckCircleIcon, SkipForwardIcon, ChatBubbleIcon, RefreshIcon } from './Icons';

interface PathfinderProps {
  sport: string;
  existingJourney: Journey | null;
  saveJourney: (journey: Journey) => void;
  goToAction: () => void;
}

const STEP_TYPE_TRANSLATIONS: Record<string, string> = {
    equipment: 'Equipamento',
    location: 'Local',
    trigger: 'Gatilho',
    'micro-goal': 'Micro-Meta'
};

export const Pathfinder: React.FC<PathfinderProps> = ({ sport, existingJourney, saveJourney, goToAction }) => {
  const [loading, setLoading] = useState(false);
  const [journey, setJourney] = useState<Journey | null>(existingJourney);

  // Chat State
  const [chatOpen, setChatOpen] = useState(false);
  const [chatMessage, setChatMessage] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user'|'model', text: string}[]>([]);
  const [chatLoading, setChatLoading] = useState(false);
  const activeStepRef = useRef<JourneyStep | null>(null);

  useEffect(() => {
    const initJourney = async () => {
      if (!existingJourney && sport) {
        setLoading(true);
        try {
          const steps = await generateJourneySteps(sport);
          const newJourney = { sport, steps };
          setJourney(newJourney);
          saveJourney(newJourney);
        } catch (e) {
            console.error(e);
            alert("Erro ao criar jornada. Tente novamente.");
        } finally {
          setLoading(false);
        }
      }
    };
    initJourney();
  }, [sport, existingJourney, saveJourney]);

  const updateStepStatus = (stepId: number, status: JourneyStep['status']) => {
    if (!journey) return;

    const newSteps = journey.steps.map(step => {
      if (step.id === stepId) return { ...step, status };
      // Unlock next step if this one is completed/skipped
      if ((status === 'completed' || status === 'skipped') && step.id === stepId + 1) {
          return { ...step, status: 'current' as const };
      }
      return step;
    });

    const newJourney = { ...journey, steps: newSteps };
    setJourney(newJourney);
    saveJourney(newJourney);
  };

  const handleChat = async () => {
    if(!chatMessage.trim()) return;

    const userMsg = chatMessage;
    setChatMessage('');
    setChatHistory(prev => [...prev, { role: 'user', text: userMsg }]);
    setChatLoading(true);

    let location: GeolocationCoordinates | undefined;

    // Only request location if user explicitly asks for 'where' or 'location' context
    // or if the current step is 'location'
    if (activeStepRef.current?.type === 'location' || userMsg.toLowerCase().includes('onde') || userMsg.toLowerCase().includes('local')) {
        try {
            const pos = await new Promise<GeolocationPosition>((resolve, reject) => {
                navigator.geolocation.getCurrentPosition(resolve, reject);
            });
            location = pos.coords;
        } catch (e) {
            console.warn("Location permission denied or error");
        }
    }

    try {
        const responseText = await getChatAssistance(
            userMsg, 
            sport, 
            activeStepRef.current?.description || "Contexto Geral",
            location
        );
        setChatHistory(prev => [...prev, { role: 'model', text: responseText }]);
    } catch (e) {
        setChatHistory(prev => [...prev, { role: 'model', text: "Desculpe, tive um problema de conexão. Tente novamente." }]);
    } finally {
        setChatLoading(false);
    }
  };

  const isJourneyComplete = journey?.steps.every(s => s.status === 'completed' || s.status === 'skipped');

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center h-[60vh]">
        <div className="animate-spin mb-4 text-purple-400">
          <MapIcon className="w-12 h-12" />
        </div>
        <p className="text-slate-300">Engenharia reversa do hábito...</p>
      </div>
    );
  }

  if (!journey) return <div className="p-6 text-center text-slate-400">Selecione um esporte na aba Explorar.</div>;

  return (
    <div className="relative min-h-screen pb-24 bg-slate-900">
      {/* Header */}
      <div className="sticky top-0 z-10 bg-slate-900/90 backdrop-blur-md p-6 border-b border-slate-800">
        <h2 className="text-2xl font-bold text-white">Desbravador: {journey.sport}</h2>
        <p className="text-slate-400 text-sm">Passo a passo logístico para começar.</p>
      </div>

      <div className="p-6 space-y-8 relative">
        {/* Vertical Line */}
        <div className="absolute left-9 top-10 bottom-10 w-0.5 bg-slate-800 -z-0" />

        {journey.steps.map((step, index) => {
          const isLocked = step.status === 'locked';
          const isDone = step.status === 'completed' || step.status === 'skipped';
          const isCurrent = step.status === 'current';

          return (
            <div key={step.id} className={`relative pl-12 transition-opacity ${isLocked ? 'opacity-40 grayscale' : 'opacity-100'}`}>
              {/* Dot Indicator */}
              <div className={`absolute left-0 top-6 w-6 h-6 rounded-full border-4 transition-colors z-10
                ${isDone ? 'bg-green-500 border-green-500' : isCurrent ? 'bg-purple-500 border-purple-500 animate-pulse' : 'bg-slate-900 border-slate-600'}
              `}>
                {isDone && <CheckCircleIcon className="w-3 h-3 text-white absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />}
              </div>

              {/* Card */}
              <div className={`bg-slate-800 rounded-xl p-5 border ${isCurrent ? 'border-purple-500/50 shadow-purple-500/20 shadow-lg' : 'border-slate-700'}`}>
                <div className="flex justify-between items-start mb-2">
                    <span className="text-xs uppercase font-bold text-slate-500 tracking-wider">
                        {STEP_TYPE_TRANSLATIONS[step.type] || step.type}
                    </span>
                    <button 
                        onClick={() => {
                            setChatOpen(true);
                            activeStepRef.current = step;
                            setChatHistory([]); // Reset chat for new context or keep history? Resetting for simplicity per step context
                        }}
                        className="text-purple-400 hover:text-purple-300"
                    >
                        <ChatBubbleIcon className="w-5 h-5" />
                    </button>
                </div>
                <h3 className="text-lg font-bold text-white mb-1">{step.title}</h3>
                <p className="text-slate-400 text-sm mb-4 leading-relaxed">{step.description}</p>

                {!isLocked && !isDone && (
                  <div className="flex space-x-3">
                    <button
                      onClick={() => updateStepStatus(step.id, 'completed')}
                      className="flex-1 bg-green-600 hover:bg-green-500 text-white py-2 rounded-lg text-sm font-medium flex items-center justify-center transition-colors"
                    >
                      <CheckCircleIcon className="w-4 h-4 mr-2" />
                      Feito
                    </button>
                    <button
                      onClick={() => updateStepStatus(step.id, 'skipped')}
                      className="flex-1 bg-slate-700 hover:bg-slate-600 text-slate-300 py-2 rounded-lg text-sm font-medium flex items-center justify-center transition-colors"
                    >
                      <SkipForwardIcon className="w-4 h-4 mr-2" />
                      Pular
                    </button>
                  </div>
                )}
                 {isDone && (
                     <div className="flex items-center text-green-400 text-sm font-medium mt-2">
                         <CheckCircleIcon className="w-4 h-4 mr-2" /> {step.status === 'skipped' ? 'Pulado' : 'Completado'}
                         <button onClick={() => updateStepStatus(step.id, 'current')} className="ml-auto text-slate-500 text-xs underline">Editar</button>
                     </div>
                 )}
              </div>
            </div>
          );
        })}
      </div>

        {/* Start Action Button */}
        {isJourneyComplete && (
            <div className="fixed bottom-20 left-0 right-0 p-6 bg-gradient-to-t from-slate-900 to-transparent">
                <button
                    onClick={goToAction}
                    className="w-full bg-rose-500 hover:bg-rose-600 text-white font-bold py-4 rounded-xl shadow-lg shadow-rose-500/30 transform hover:scale-[1.02] transition-all"
                >
                    Ir para Ação &rarr;
                </button>
            </div>
        )}

      {/* Chat Modal */}
      {chatOpen && (
        <div className="fixed inset-0 z-50 bg-black/80 flex items-center justify-center p-4">
          <div className="bg-slate-800 w-full max-w-md h-[70vh] rounded-2xl flex flex-col overflow-hidden shadow-2xl border border-slate-700">
            <div className="p-4 bg-slate-900 border-b border-slate-700 flex justify-between items-center">
              <h3 className="text-white font-bold flex items-center">
                  <ChatBubbleIcon className="w-5 h-5 mr-2 text-purple-400" />
                  Assistente IA
              </h3>
              <button onClick={() => setChatOpen(false)} className="text-slate-400 hover:text-white">✕</button>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-4">
                {chatHistory.length === 0 && (
                    <div className="text-center text-slate-500 mt-10">
                        <p>Dúvidas sobre {STEP_TYPE_TRANSLATIONS[activeStepRef.current?.type || ''] || activeStepRef.current?.type}?</p>
                        <p className="text-xs mt-2">Ex: "Onde encontrar {activeStepRef.current?.type === 'equipment' ? 'equipamentos' : 'locais'} baratos?"</p>
                    </div>
                )}
                {chatHistory.map((msg, i) => (
                    <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[85%] p-3 rounded-lg text-sm ${
                            msg.role === 'user' ? 'bg-purple-600 text-white rounded-br-none' : 'bg-slate-700 text-slate-200 rounded-bl-none prose prose-invert prose-p:my-1 prose-a:text-teal-400'
                        }`}>
                             {/* Very basic markdown rendering for links */}
                             {msg.role === 'model' ? (
                                <div dangerouslySetInnerHTML={{ 
                                    __html: msg.text.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
                                                    .replace(/\n/g, '<br/>')
                                                    .replace(/- \[(.*?)\]\((.*?)\)/g, '• <a href="$2" target="_blank" rel="noopener noreferrer">$1</a>')
                                }} />
                             ) : msg.text}
                        </div>
                    </div>
                ))}
                {chatLoading && <div className="text-slate-500 text-xs animate-pulse">Digitando...</div>}
            </div>

            <div className="p-4 bg-slate-900 border-t border-slate-700">
                <div className="flex space-x-2">
                    <input 
                        type="text" 
                        value={chatMessage}
                        onChange={(e) => setChatMessage(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleChat()}
                        placeholder="Pergunte algo..."
                        className="flex-1 bg-slate-800 border border-slate-600 text-white rounded-lg px-4 py-2 text-sm focus:outline-none focus:border-purple-500"
                    />
                    <button onClick={handleChat} disabled={chatLoading} className="bg-purple-600 text-white p-2 rounded-lg hover:bg-purple-500 disabled:opacity-50">
                        ➤
                    </button>
                </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Journey } from '../types';
import { PlayIcon, CalendarIcon, DumbbellIcon, CheckCircleIcon } from './Icons';

interface ActionCenterProps {
  journey: Journey | null;
}

export const ActionCenter: React.FC<ActionCenterProps> = ({ journey }) => {
  const [timerActive, setTimerActive] = useState(false);
  const [timeLeft, setTimeLeft] = useState(10 * 60); // 10 minutes
  const [sessionComplete, setSessionComplete] = useState(false);
  const [selectedDay, setSelectedDay] = useState<string | null>(null);

  // Ref to hold the interval ID so we can clear it on unmount or stop
  const timerRef = useRef<number | null>(null);

  // Cleanup timer on unmount
  useEffect(() => {
    return () => {
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    };
  }, []);

  // Timer logic controlled by state
  useEffect(() => {
    if (timerActive) {
      timerRef.current = window.setInterval(() => {
        setTimeLeft((prev) => {
          if (prev <= 1) {
            if (timerRef.current) clearInterval(timerRef.current);
            setTimerActive(false);
            setSessionComplete(true);
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    } else if (timerRef.current) {
      clearInterval(timerRef.current);
    }
  }, [timerActive]);

  // Mock calendar days
  const nextDays = Array.from({ length: 5 }, (_, i) => {
    const d = new Date();
    d.setDate(d.getDate() + i);
    return {
      label: d.toLocaleDateString('pt-BR', { weekday: 'short' }).slice(0, 3),
      date: d.getDate(),
      fullDate: d.toISOString().split('T')[0]
    };
  });

  const toggleTimer = () => {
    setTimerActive(!timerActive);
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s < 10 ? '0' : ''}${s}`;
  };

  const handleAddToCalendar = () => {
    if (!selectedDay || !journey) return;

    // Format date for ICS (YYYYMMDD)
    const dateStr = selectedDay.replace(/-/g, '');
    const startTime = '090000'; // 09:00 AM
    const endTime = '093000'; // 09:30 AM

    const icsContent = [
      'BEGIN:VCALENDAR',
      'VERSION:2.0',
      'PRODID:-//NeuroFlow//Habit App//PT',
      'BEGIN:VEVENT',
      `UID:${Date.now()}@neuroflow.app`,
      `DTSTAMP:${new Date().toISOString().replace(/[-:]/g, '').split('.')[0]}Z`,
      `DTSTART:${dateStr}T${startTime}`,
      `DTEND:${dateStr}T${endTime}`,
      `SUMMARY:NeuroFlow: ${journey.sport} Micro-Meta`,
      `DESCRIPTION:Hora de executar seu passo de ${journey.sport}. Lembre-se: foque no gatilho e na micro-meta!`,
      'END:VEVENT',
      'END:VCALENDAR'
    ].join('\r\n');

    const blob = new Blob([icsContent], { type: 'text/calendar;charset=utf-8' });
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `neuroflow-${journey.sport}-${selectedDay}.ics`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  if (!journey) {
    return (
      <div className="flex flex-col items-center justify-center h-[80vh] px-6 text-center">
        <DumbbellIcon className="w-16 h-16 text-slate-700 mb-4" />
        <h2 className="text-xl font-bold text-slate-400">Nenhum plano ativo</h2>
        <p className="text-slate-500 mt-2">Vá para "Explorar" para descobrir seu esporte.</p>
      </div>
    );
  }

  return (
    <div className="p-6 pb-24 min-h-screen bg-slate-900">
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-white">Centro de Ação</h1>
        <p className="text-slate-400">Objetivo: <span className="text-teal-400 font-medium">{journey.sport}</span></p>
      </div>

      {/* Scheduler */}
      <div className="bg-slate-800 rounded-2xl p-6 mb-8 shadow-lg border border-slate-750">
        <div className="flex items-center mb-4 text-rose-400">
            <CalendarIcon className="w-5 h-5 mr-2" />
            <h3 className="font-bold uppercase tracking-wide text-sm">Agendar Micro-Meta</h3>
        </div>
        <p className="text-slate-400 text-sm mb-4">Escolha um dia para executar seu gatilho.</p>
        <div className="flex justify-between">
            {nextDays.map((day) => (
                <button
                    key={day.fullDate}
                    onClick={() => setSelectedDay(day.fullDate)}
                    className={`flex flex-col items-center justify-center w-12 h-14 rounded-lg transition-all ${
                        selectedDay === day.fullDate 
                        ? 'bg-rose-500 text-white shadow-lg shadow-rose-500/25 scale-110' 
                        : 'bg-slate-700 text-slate-400 hover:bg-slate-600'
                    }`}
                >
                    <span className="text-[10px] uppercase font-bold">{day.label}</span>
                    <span className="text-lg font-bold">{day.date}</span>
                </button>
            ))}
        </div>
        {selectedDay && (
            <div className="mt-4 p-4 bg-rose-500/10 border border-rose-500/20 rounded-lg text-center animate-fade-in">
                <p className="text-rose-200 text-sm font-medium mb-3">
                  Agendado!
                </p>
                <button 
                  onClick={handleAddToCalendar}
                  className="bg-rose-500 hover:bg-rose-600 text-white text-xs font-bold py-2 px-4 rounded-full inline-flex items-center transition-colors shadow-lg shadow-rose-500/20 active:scale-95"
                >
                  <CalendarIcon className="w-4 h-4 mr-2" />
                  Adicionar ao Calendário
                </button>
            </div>
        )}
      </div>

      {/* Timer Section */}
      <div className="bg-gradient-to-br from-slate-800 to-slate-900 rounded-2xl p-8 text-center border border-slate-700 shadow-2xl relative overflow-hidden">
        {/* Decorative circle */}
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-teal-500 via-purple-500 to-rose-500"></div>

        <h3 className="text-white font-bold text-lg mb-2">Sessão Rápida</h3>
        <p className="text-slate-400 text-sm mb-8">10 minutos de foco total ou apenas preparação.</p>

        {sessionComplete ? (
            <div className="animate-fade-in py-10">
                <CheckCircleIcon className="w-20 h-20 text-green-500 mx-auto mb-4" />
                <h2 className="text-2xl font-bold text-white">Vitória!</h2>
                <p className="text-slate-300 mt-2">Dopamina liberada com sucesso.</p>
                <button 
                    onClick={() => { setSessionComplete(false); setTimeLeft(600); }}
                    className="mt-6 text-sm text-slate-500 hover:text-white underline"
                >
                    Reiniciar
                </button>
            </div>
        ) : (
            <>
                <div className="text-6xl font-mono font-bold text-white mb-8 tracking-wider tabular-nums">
                    {formatTime(timeLeft)}
                </div>

                <button
                    onClick={toggleTimer}
                    className={`w-20 h-20 rounded-full flex items-center justify-center mx-auto transition-all shadow-xl ${
                        timerActive 
                        ? 'bg-slate-700 text-rose-500 border-2 border-rose-500 animate-pulse' 
                        : 'bg-rose-500 hover:bg-rose-600 text-white scale-100 hover:scale-105'
                    }`}
                >
                    {timerActive ? (
                        <div className="w-6 h-6 bg-current rounded-sm" /> 
                    ) : (
                        <PlayIcon className="w-8 h-8 ml-1" />
                    )}
                </button>
                <p className="text-xs text-slate-500 mt-6 uppercase tracking-widest">
                    {timerActive ? "Em progresso..." : "Iniciar"}
                </p>
            </>
        )}
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { Archetype, JourneyStep, QuizAnswer } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Model constants
const FLASH_MODEL = 'gemini-2.5-flash';

/**
 * Analyzes quiz answers to determine the user's Neuro-Archetype.
 */
export const analyzeNeuroArchetype = async (answers: QuizAnswer[]): Promise<Archetype> => {
  const prompt = `
    Analise as seguintes respostas detalhadas de um usuário para uma avaliação de "Neuro-Compatibilidade" de exercícios.
    Os dados incluem bateria social, ambiente preferido, estilo de foco, necessidades de liberação de agressividade, preferência por estrutura, fonte de motivação, tolerância à dor e hábitos com equipamentos.

    Com base neste perfil abrangente, RETORNE EM PORTUGUÊS DO BRASIL:
    1. Atribua um "Nome de Arquétipo" criativo e impactante (ex: O Estrategista Zen, O Gladiador Social, O Solista da Natureza).
    2. Explique a neurociência/psicologia por trás disso (Por que essa pessoa falha em academias comuns? Quais neuroquímicos específicos como Dopamina/Serotonina/Endorfina ela busca baseada nas respostas?).
    3. Sugira 3 esportes/atividades específicos que sejam um par perfeito. Evite sugestões genéricas; seja específico (ex: em vez de "corrida", sugira "Trail Running" ou "Sprints" baseado nas respostas).

    Respostas do Usuário:
    ${answers.map(a => `- Contexto: ${a.category}, Escolha: ${a.selectedOption}`).join('\n')}
  `;

  const response = await ai.models.generateContent({
    model: FLASH_MODEL,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          description: { type: Type.STRING },
          neurochemistry: { type: Type.STRING },
          suggestedSports: { 
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["name", "description", "neurochemistry", "suggestedSports"]
      }
    }
  });

  return JSON.parse(response.text || "{}") as Archetype;
};

/**
 * Generates the "Pathfinder" journey steps for a specific sport.
 */
export const generateJourneySteps = async (sport: string): Promise<JourneyStep[]> => {
  const prompt = `
    Crie um plano de formação de hábito com "Engenharia Reversa" para um iniciante querendo começar: ${sport}.
    Quebre em exatamente 4 passos logísticos, evitando o treino real até o final.
    RETORNE EM PORTUGUÊS DO BRASIL.

    Os passos devem ser exatamente destes tipos, nesta ordem:
    1. equipment (Equipamento necessário - Gear needed)
    2. location (Local onde fazer - Where to do it)
    3. trigger (A ação preparatória - The preparatory action, ex: separar as roupas)
    4. micro-goal (Uma primeira meta minúscula e não intimidadora, ex: "Apenas calçar o tênis")

    Retorne um array JSON de passos com titulo e descrição em PT-BR.
  `;

  const response = await ai.models.generateContent({
    model: FLASH_MODEL,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.INTEGER },
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            type: { type: Type.STRING, enum: ["equipment", "location", "trigger", "micro-goal"] }
          },
          required: ["id", "title", "description", "type"]
        }
      }
    }
  });

  const rawSteps = JSON.parse(response.text || "[]");

  // Hydrate with initial status
  return rawSteps.map((s: any, index: number) => ({
    ...s,
    id: index + 1,
    status: index === 0 ? 'current' : 'locked' // First step is current, others locked
  }));
};

/**
 * Chat assistant for the Journey tab.
 * Uses Google Maps tool for location queries.
 */
export const getChatAssistance = async (
  message: string, 
  currentSport: string, 
  currentStepContext: string,
  userLocation?: GeolocationCoordinates
) => {

  let toolConfig = undefined;

  // Add tools if relevant
  if (userLocation) {
      toolConfig = {
          retrievalConfig: {
              latLng: {
                  latitude: userLocation.latitude,
                  longitude: userLocation.longitude
              }
          }
      }
  }

  const systemInstruction = `
    Você é um assistente de coach de hábitos solidário e ciente da neurociência chamado "NeuroFlow Bot".
    O usuário está tentando iniciar o hábito de ${currentSport}.
    Ele está atualmente travado no passo: "${currentStepContext}".
    Mantenha as respostas curtas, encorajadoras e práticas.
    Fale sempre em Português do Brasil.
    Se perguntarem sobre locais, use a ferramenta Google Maps para encontrar lugares reais próximos.
    Se perguntarem sobre equipamentos, dê opções econômicas e "pro".
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash', // Use flash for speed, maps tool is available on flash
    contents: message,
    config: {
        systemInstruction: systemInstruction,
        tools: [{ googleMaps: {} }],
        toolConfig: toolConfig
    }
  });

  // Extract text and potential map links
  let text = response.text || "";
  const mapChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

  // Append map links to text if they exist (simple formatting)
  if (mapChunks.length > 0) {
      text += "\n\n**Sugestões de Locais:**\n";
      mapChunks.forEach((chunk: any) => {
          // Check for maps first (Google Maps Tool), then fallback to web
          if (chunk.maps?.uri) {
             text += `- [${chunk.maps.title}](${chunk.maps.uri})\n`;
          } else if (chunk.web?.uri) {
             text += `- [${chunk.web.title}](${chunk.web.uri})\n`;
          }
      });
  }

  return text;
};

